import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import axiosInstance from '../../api/axiosInstance';

const VerifyEmailSent = () => {
    const location = useLocation();
    const searchParams = new URLSearchParams(location.search);
    const email = searchParams.get('email') || (location.state && location.state.email) || 'your email';

    const [resendStatus, setResendStatus] = useState(''); // 'sending', 'sent', 'error'
    const [resendMessage, setResendMessage] = useState('');

    const handleResend = async () => {
        if (!email || email === 'your email') return;

        setResendStatus('sending');
        setResendMessage('Sending...');

        try {
            await axiosInstance.post('/auth/resend-verification/', { email });
            setResendStatus('sent');
            setResendMessage('Verification email resent!');
        } catch (error) {
            setResendStatus('error');
            setResendMessage(error.response?.data?.error || 'Failed to resend email.');
        }
    };

    return (
        <div className="d-flex align-items-center justify-content-center vh-100 bg-light">
            <div className="card shadow p-5 text-center" style={{ maxWidth: '600px', width: '90%' }}>
                <div className="mb-4">
                    <i className="bi bi-envelope-check-fill text-success display-1"></i>
                </div>

                <h2 className="mb-3 text-primary">Verify Your Email</h2>

                <p className="lead mb-4">
                    We've sent a verification email to: <br />
                    <strong>{email}</strong>
                </p>

                <p className="text-muted mb-4">
                    Please check your inbox and click the link to verify your account.
                    The link will expire in 24 hours.
                </p>

                <div className="d-grid gap-2 col-md-8 mx-auto">
                    <Link to="/login" className="btn btn-primary">
                        Proceed to Login
                    </Link>

                    <div className="mt-3">
                        <p className="small text-muted mb-2">Didn't receive the email? Check your spam folder or:</p>
                        <button
                            className="btn btn-outline-secondary btn-sm"
                            onClick={handleResend}
                            disabled={resendStatus === 'sending' || resendStatus === 'sent' || email === 'your email'}
                        >
                            {resendStatus === 'sending' ? 'Sending...' : 'Resend Verification Email'}
                        </button>
                        {resendMessage && (
                            <p className={`small mt-2 ${resendStatus === 'error' ? 'text-danger' : 'text-success'}`}>
                                {resendMessage}
                            </p>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default VerifyEmailSent;
